    privacy:{title:'سياسة الخصوصية — RelahConvert',hero_h1_1:'سياسة',hero_h1_em:'الخصوصية',updated:'مارس 2026',s1_h:'لا رفع للملفات',s1_p:'تتم معالجة الصور محلياً في متصفحك. ملفاتك لا تُرفع إلى خوادمنا أبداً. استثناء: أداة HTML إلى صورة ترسل الرابط الذي تُدخله إلى خدمة طرف ثالث لالتقاط الصفحة — أنت لا ترفع أي ملف صورة.',s2_h:'البيانات',s2_p1:'بيانات استخدام مجهولة.',s2_p2:'لا معلومات شخصية.',s3_h:'الكوكيز',s3_p:'الكوكيز الأساسية فقط. راجع <a href="/cookies">السياسة</a>.',s4_h:'أطراف ثالثة',s4_p:'لا نبيع بياناتك.'},
