        links:[{href:'/compress',label:'이미지 압축'},{href:'/resize',label:'이미지 크기 변경'},{href:'/crop',label:'이미지 자르기'},{href:'/watermark',label:'워터마크 추가'},{href:'/jpg-to-png',label:'JPG를 PNG로'}],
