    blur_face_title:'Yüz',blur_face_title_em:'bulanıklaştırma',blur_face_sub:'Fotoğraflardaki yüzleri bulanıklaştırın. Otomatik algılama veya manuel seçim. 25 görsele kadar. Gizli — tarayıcınızda çalışır.',blur_face_upload:'Görsel yükle',blur_face_download:'Görseli indir',blur_face_amount:'Bulanıklık miktarı',blur_face_detecting:'Yüzler algılanıyor…',blur_face_none:'Yüz bulunamadı. Daha net bir fotoğraf deneyin veya Bulanıklık Ekle\'yi kullanın.',blur_face_found:'yüz bulundu',blur_face_manual:'Bulanıklık ekle',blur_face_auto:'Otomatik algılama',blur_face_mode:'Mod',blur_face_select_mode:'Başlamak için bir mod seçin.',blur_face_draw:'Bir alanı bulanıklaştırmak için görsele tıklayıp sürükleyin.',blur_face_editor:'Bulanıklaştırma düzenleyici',blur_face_regions:'Bulanıklaştırılmış alanlar',blur_face_download_zip:'Tümünü ZIP olarak indir',blur_face_reset:'Yeni görsel yükle',blur_face_images_label:'Görseller',blur_face_drop:'Görselleri buraya bırakın veya yüklemek için tıklayın',blur_face_drop_sub:'JPG, PNG, WebP · 25 görsele kadar · Maks 200MB',blur_face_processing:'İşleniyor',blur_face_creating_zip:'ZIP oluşturuluyor…',blur_face_batch_failed:'Toplu indirme başarısız oldu',
